import { useState, useRef, useEffect } from 'react'
import {
  Box,
  TextField,
  Button,
  Typography,
  CircularProgress,
  Paper,
  Divider,
} from '@mui/material'
import SendIcon from '@mui/icons-material/Send'
import SmartToyOutlinedIcon from '@mui/icons-material/SmartToyOutlined'

// Generated by: npm run generate-api
import { useAiChat } from '../../../api/ai/ai'
import { useUpdateDesign } from '../../../api/designs/designs'
import { useDesignStore } from '../designStore'
import { ChatMessage } from '../../../types'

const HINTS = [
  'Design a basic e-commerce backend',
  'Add a Redis cache in front of the database',
  'What are the bottlenecks in this design?',
]

export default function AIChat() {
  const { nodes, edges, activeDesignId, applyAIActions } = useDesignStore()
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [input, setInput] = useState('')
  const bottomRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  useEffect(() => {
    setMessages([])
  }, [activeDesignId])

  const { mutate: updateDesign } = useUpdateDesign()

  const { mutate: aiChat, isPending } = useAiChat({
    mutation: {
      onSuccess: (data) => {
        setMessages((m) => [...m, { role: 'assistant', content: data.message }])
        if (data.actions.length > 0) {
          applyAIActions(data.actions)
          setTimeout(() => {
            const { nodes: n, edges: e, activeDesignId: id } = useDesignStore.getState()
            if (id) updateDesign({ designId: id, data: { nodes: n, edges: e } })
          }, 100)
        }
      },
      onError: (err: unknown) => {
        const msg =
          (err as { response?: { data?: { detail?: string } } })?.response?.data?.detail ??
          'An error occurred. Please try again.'
        setMessages((m) => [...m, { role: 'assistant', content: `Error: ${msg}` }])
      },
    },
  })

  const send = () => {
    if (!input.trim() || isPending || !activeDesignId) return
    const userMsg = input.trim()
    setInput('')
    setMessages((m) => [...m, { role: 'user', content: userMsg }])
    aiChat({ data: { message: userMsg, nodes, edges } })
  }

  return (
    <Box
      sx={{
        width: 288,
        flexShrink: 0,
        display: 'flex',
        flexDirection: 'column',
        borderLeft: 1,
        borderColor: 'divider',
        bgcolor: 'background.paper',
      }}
    >
      {/* Header */}
      <Box sx={{ px: 2, py: 1.5, borderBottom: 1, borderColor: 'divider' }}>
        <Typography variant="subtitle2" fontWeight={600}>
          AI Assistant
        </Typography>
        <Typography variant="caption" color="text.secondary">
          Describe your system or ask for changes
        </Typography>
      </Box>

      {/* Messages */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 1.5, display: 'flex', flexDirection: 'column', gap: 1 }}>
        {messages.length === 0 && (
          <Box sx={{ textAlign: 'center', mt: 3 }}>
            <SmartToyOutlinedIcon sx={{ fontSize: 40, color: 'text.disabled', mb: 1 }} />
            <Typography variant="caption" color="text.secondary" display="block" sx={{ lineHeight: 1.6 }}>
              Describe a system and I'll build it on the canvas, or ask me to modify the current
              design.
            </Typography>
            <Box sx={{ mt: 2, display: 'flex', flexDirection: 'column', gap: 0.5, textAlign: 'left' }}>
              {HINTS.map((hint) => (
                <Button
                  key={hint}
                  size="small"
                  variant="text"
                  disabled={!activeDesignId}
                  onClick={() => setInput(hint)}
                  sx={{ justifyContent: 'flex-start', fontSize: 11, textTransform: 'none', color: 'primary.main' }}
                >
                  "{hint}"
                </Button>
              ))}
            </Box>
          </Box>
        )}

        {messages.map((msg, i) => (
          <Box
            key={i}
            sx={{ display: 'flex', justifyContent: msg.role === 'user' ? 'flex-end' : 'flex-start' }}
          >
            <Paper
              elevation={0}
              sx={{
                px: 1.5,
                py: 1,
                maxWidth: '90%',
                fontSize: 12,
                lineHeight: 1.6,
                bgcolor: msg.role === 'user' ? 'primary.main' : 'action.hover',
                color: msg.role === 'user' ? 'primary.contrastText' : 'text.primary',
                borderRadius: 2,
              }}
            >
              {msg.content}
            </Paper>
          </Box>
        ))}

        {isPending && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <CircularProgress size={14} />
            <Typography variant="caption" color="text.secondary">
              Thinking...
            </Typography>
          </Box>
        )}

        <div ref={bottomRef} />
      </Box>

      <Divider />

      {/* Input */}
      <Box sx={{ p: 1.5, display: 'flex', gap: 1 }}>
        <TextField
          size="small"
          fullWidth
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && send()}
          placeholder={activeDesignId ? 'Ask AI...' : 'Select a design first'}
          disabled={!activeDesignId || isPending}
          inputProps={{ style: { fontSize: 12 } }}
        />
        <Button
          variant="contained"
          size="small"
          onClick={send}
          disabled={!input.trim() || isPending || !activeDesignId}
          sx={{ minWidth: 0, px: 1.5 }}
        >
          <SendIcon fontSize="small" />
        </Button>
      </Box>
    </Box>
  )
}
